public class Solution {
    // Post-order: children first, then parent
    public int maxDepth(TreeNode root) {
        if (root == null) return 0;           // base case: empty tree
        int leftH  = maxDepth(root.left);     // depth of left subtree
        int rightH = maxDepth(root.right);    // depth of right subtree
        return 1 + Math.max(leftH, rightH);   // current node + taller child
    }

    // Iterative (BFS approach):
    public int maxDepthBFS(TreeNode root) {
        if (root == null) return 0;
        Queue<TreeNode> q = new LinkedList<>();
        q.offer(root);
        int depth = 0;
        while (!q.isEmpty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                TreeNode node = q.poll();
                if (node.left  != null) q.offer(node.left);
                if (node.right != null) q.offer(node.right);
            }
            depth++;
        }
        return depth;
    }
}

